use std::mem;

struct Position { 
    x: f32, 
    y: f32, 
}

struct Velocity { 
    vx: f32, 
    vy: f32,
}

fn process_data(raw_bytes: &mut [u8]) -> Result<(), std::io::Error> {
    let len = raw_bytes.len();
    if len % 16 != 0 { 
        return Err(std::io::Error::new(std::io::ErrorKind::InvalidData, "Data size mismatch"));
    }

    unsafe {
        let position_slice: *mut Position = raw_bytes.as_mut_ptr() as *mut Position;
        let velocity_slice: *mut Velocity = raw_bytes.as_mut_ptr() as *mut Velocity;

        let num_elements = len / 16;

        let positions = std::slice::from_raw_parts(position_slice, num_elements);
        let velocities = std::slice::from_raw_parts(velocity_slice, num_elements);

        for i in 0..num_elements {
            println!("Position {}: ({:.2}, {:.2})", i, positions[i].x, positions[i].y);
            println!("Velocity {}: ({:.2}, {:.2})", i, velocities[i].vx, velocities[i].vy);
        }
    }
    Ok(())
}

